games.description:
(game "Excellent Rich Okapi  Simple"
    (players 2)

    (equipment
        (board (square 5))
    )

    (rules

        (play
            (repeat (P1 P2)
                (place
                    (destination empty)
                    (effects
                        (capture (custodial 1)
                                 increment_score:true)
                    )
                )
            )
        )


        (end
            (if (>= (score mover) 5) (mover win))
            (if (full_board) (draw))
        )
    )
)

(game "Excellent Rich Okapi  Line Bonus"
    (players 2)

    (equipment
        (board (square 5))
    )

    (rules
        (play
            (repeat (P1 P2)
                (place
                    (destination empty)


                    (result (line 3))

                    (effects
                        (capture (custodial 1) increment_score:true)


                        (increment_score mover (add (constant 1) (constant 0)))
                    )
                )
            )
        )

        (end
            (if (>= (score mover) 5) (mover win))
            (if (full_board) (draw))
        )
    )
)
